import "jsr:@supabase/functions-js/edge-runtime.d.ts";

import { createClient } from "https://esm.sh/@supabase/supabase-js@2";

const COINGECKO_URL =
  "https://api.coingecko.com/api/v3/coins/bitcoin/market_chart?vs_currency=usd&days=7&interval=daily";

type PriceEntry = [number, number];

function jsonResponse(body: unknown, status = 200): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      "Content-Type": "application/json",
      Connection: "keep-alive",
    },
  });
}

/** Start of day UTC for a given timestamp (ms). */
function toDateUtcIso(tsMs: number): string {
  const d = new Date(tsMs);
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, "0");
  const day = String(d.getUTCDate()).padStart(2, "0");
  return `${y}-${m}-${day}T00:00:00.000Z`;
}

Deno.serve(async (_req: Request) => {
  const url = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
  if (!url || !serviceRoleKey) {
    return jsonResponse(
      { error: "Missing SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY" },
      500,
    );
  }

  const supabase = createClient(url, serviceRoleKey);

  try {
    const res = await fetch(COINGECKO_URL, {
      headers: { Accept: "application/json" },
    });
    if (!res.ok) {
      const text = await res.text().catch(() => "");
      throw new Error(`Upstream error: ${res.status} ${text}`);
    }

    const json = (await res.json()) as { prices?: PriceEntry[] };
    const prices = json.prices;
    if (!Array.isArray(prices) || prices.length === 0) {
      throw new Error("Upstream chart payload missing or empty prices");
    }

    const rows = prices
      .filter(
        (entry): entry is PriceEntry =>
          Array.isArray(entry) &&
          entry.length >= 2 &&
          typeof entry[0] === "number" &&
          typeof entry[1] === "number",
      )
      .map(([tsMs, value]) => ({
        date_utc: toDateUtcIso(tsMs),
        value: Number(value),
      }));

    if (rows.length === 0) {
      throw new Error("No valid price entries");
    }

    const { error } = await supabase
      .from("chart_trending_points")
      .upsert(rows, { onConflict: "date_utc" });
    if (error) throw error;

    const points = rows.map((r) => ({
      date_utc: r.date_utc,
      value: r.value,
    }));
    return jsonResponse({ points, synced: rows.length });
  } catch (e) {
    const message = e instanceof Error ? e.message : String(e);
    return jsonResponse({ error: message }, 502);
  }
});
